localparam IDLE = 2'd0;
localparam ROTATE = 2'd1;
localparam DONE = 2'd2;
always @(posedge clk) begin
    case (state)
        IDLE: x <= 1;
        ROTATE: x <= 2;
        DONE: x <= 3;
    endcase
end

localparam IDLE = 2'd0;
localparam ROTATE = 2'd1;
localparam DONE = 2'd2;
always @(posedge clk) begin
    if (state == IDLE) x <= 1;
    else if (state == ROTATE) x <= 2;
    else if (state == DONE) x <= 3;
end
